1	const PROCESSING_FEE = 5;
2	
3	type Item = { type: string; cursed?: boolean };
4	type QuoteStep = { op: "quote"; items: Item[] };
5	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
6	type StepResult = { premium: number };
7	type ScenarioResult = { results: StepResult[] };
8	
9	const BASE_PRICES: Record<string, number> = {
10	  sword: 100,
11	  amulet: 60,
12	  staff: 80,
13	  potion: 40,
14	  rune: 25,
15	  moonstone: 25,
16	};
17	
18	const basePriceOf = (item: Item): number => BASE_PRICES[item.type] ?? 0;
19	
20	const itemPremium = (item: Item): number => {
21	  const base = basePriceOf(item);
22	  const cursedSurcharge = item.cursed ? base * 0.5 : 0;
23	  return base + cursedSurcharge;
24	};
25	
26	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
27	const BLOCK_SIZE = 3;
28	const BLOCK_PRICE = 60;
29	
30	const groupByType = (items: Item[]): Map<string, Item[]> => {
31	  const groups = new Map<string, Item[]>();
32	  for (const item of items) {
33	    const existing = groups.get(item.type) ?? [];
34	    existing.push(item);
35	    groups.set(item.type, existing);
36	  }
37	  return groups;
38	};
39	
40	const groupBasePrice = (type: string, members: Item[]): number => {
41	  if (COMPONENT_TYPES.has(type) && members.length === BLOCK_SIZE) return BLOCK_PRICE;
42	  return members.reduce((sum, item) => sum + itemPremium(item), 0);
43	};
44	
45	const sumBasePrices = (items: Item[]): number =>
46	  Array.from(groupByType(items)).reduce(
47	    (total, [type, members]) => total + groupBasePrice(type, members),
48	    0,
49	  );
50	
51	const quotePremium = (items: Item[]): number =>
52	  sumBasePrices(items) + PROCESSING_FEE;
53	
54	const runStep = (step: QuoteStep): StepResult => ({
55	  premium: quotePremium(step.items),
56	});
57	
58	export const runScenario = (input: Scenario): ScenarioResult => ({
59	  results: input.steps.map(runStep),
60	});
